import { useEffect, useState } from "react";
import API from "../api/axios";

function Dashboard() {

  const [data, setData] = useState({
    totalIncome: 0,
    totalExpense: 0,
    balance: 0
  });

  useEffect(() => {
    const fetchDashboard = async () => {
      try {
        const res = await API.get("/dashboard");
        setData(res.data);
      } catch (error) {
        console.log(error);
      }
    };

    fetchDashboard();
  }, []);

  return (
    <div style={{ padding: "20px" }}>
      <h2>Dashboard</h2>

      <div style={{
        display: "flex",
        gap: "20px",
        marginTop: "20px"
      }}>

        {/* Balance Card */}
        <div style={cardStyle}>
          <h3>Balance</h3>
          <p>₹ {data.balance}</p>
        </div>

        {/* Income Card */}
        <div style={{...cardStyle, backgroundColor: "#d4edda"}}>
          <h3>Income</h3>
          <p>₹ {data.totalIncome}</p>
        </div>

        {/* Expense Card */}
        <div style={{...cardStyle, backgroundColor: "#f8d7da"}}>
          <h3>Expense</h3>
          <p>₹ {data.totalExpense}</p>
        </div>

      </div>
    </div>
  );
}

const cardStyle = {
  flex: 1,
  padding: "20px",
  borderRadius: "10px",
  backgroundColor: "#e2e3e5",
  boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
  textAlign: "center"
};

export default Dashboard;
